import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface WeeklyPlaytime {
  day: string;
  hours: number;
}

interface GamingStats {
  game: string;
  playtime: {
    totalHours: number;
    hoursThisWeek: number;
  };
  achievements: {
    total: number;
    unlocked: number;
  };
  levelProgress: {
    currentLevel: number;
    experiencePoints: number;
    nextLevelPoints: number;
  };
  weeklyPlaytime: WeeklyPlaytime[];
}

export default function Widget() {
  const gamingData = response.data as GamingStats;
  const { game, playtime, achievements, levelProgress, weeklyPlaytime } = gamingData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E1E1E', color: '#FFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1 }}>
              {game}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Total Playtime: {playtime.totalHours} hrs
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              This Week: {playtime.hoursThisWeek} hrs
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Achievements Unlocked: {achievements.unlocked}/{achievements.total}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Level: {levelProgress.currentLevel}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              XP: {levelProgress.experiencePoints}/{levelProgress.nextLevelPoints}
            </Typography>
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: weeklyPlaytime.map(d => d.hours),
                color: '#673AB7',
              },
            ]}
            xAxis={[
              {
                data: weeklyPlaytime.map(d => d.day),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#FFF',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
